class SymbolGC
  def initialize
    @found = [[SLOT set_init]]
    @live = Set.new
  end

  def register_code(snippet)
    # Match :symbol and :'quoted symbol'
    snippet.scan([[SLOT quoted_regex]]).each do |quoted, unquoted|
      @found.add((quoted || unquoted).to_sym)
    end

    # Match %i[sym1 sym2] and %I[sym1 sym2]
    snippet.scan([[SLOT array_regex]]).each do |match|
      match[0].split.each { |s| @found.add(s.to_sym) }
    end

    # Match hash syntax key: value
    snippet.scan(/([a-zA-Z_]\w*):\s+/).each do |match|
      @found.add(match[0].to_sym)
    end
  end

  def mark_live(*syms)
    syms.each { |s| @live.add(s) }
  end

  def unreferenced
    [[SLOT unref_calc]]
  end
end
